        // Preserve old property name for backward compat with existing documents.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Id format changed from "EntityType|Key" to just "Key" in 9.0.
        // Preserve old id format for existing documents.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyCosmosIdGenerator>();

        // Breaking change 3: Cosmos DB does not support indexes defined via EF Core.
        // HasIndex() now throws in 9.0 instead of silently ignoring.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}
